vector<int> levelOrder(TreeNode* root){
    vector<int> res;
    if(!root)return res;
    queue<TreeNode*> q;q.push(root);
    while(!q.empty()){
        TreeNode* node=q.front();q.pop();
        if(node){res.push_back(node->val);q.push(node->left);q.push(node->right);}
        else res.push_back(INT_MIN);
    }
    while(!res.empty()&&res.back()==INT_MIN)res.pop_back();
    return res;
}

